def P(**kw):
    d = {"aiImagePrompt":"古风水墨画，中国古典诗词意境：%(title)s %(author)s，朦胧山水，云雾缭绕" % kw,
         "aiImageUrl":"","historicalPaintings":[],"calligraphyUrls":[],"quizIds":[],
         "schoolLevel":"","schoolTextbook":"","theme":[],"relatedPoemIds":[]}
    d.update(kw)
    return d

AUTHORS = []
POEMS = []

def A(id, name, nickname, dynasty, bio, birth=None, death=None):
    AUTHORS.append({"id":id,"name":name,"nickname":nickname,"dynasty":dynasty,
                    "birthYear":birth,"deathYear":death,"bio":bio,
                    "representativeWorks":[],"portraitUrl":""})

def poem(id, title, author, author_id, dynasty, cat, diff, content, translation,
         annotation="", background="", tags=None, source="", sl="", stb="", theme=None):
    POEMS.append(P(id=id,title=title,author=author,authorId=author_id,
                   dynasty=dynasty,category=cat,difficulty=diff,
                   content=content,translation=translation,annotation=annotation,
                   background=background,tags=tags or [],source=source,
                   schoolLevel=sl,schoolTextbook=stb,theme=theme or []))

